        for cat in raw_cats:
            cat = cat.strip()
            if cat:
                categories.append(cat)
    elif 'services, including' in description:
        service_part = description.split('services, including')[1]
        service_part = service_part.split('.')[0]
        raw_cats = re.split(r',|, and|and', service_part)
        for cat in raw_cats:
            cat = cat.strip()
            if cat:
                categories.append(cat)
    elif 'services including' in description:
        service_part = description.split('services including')[1]
        service_part = service_part.split('.')[0]
        raw_cats = re.split(r',|, and|and', service_part)
        for cat in raw_cats:
            cat = cat.strip()
            if cat:
                categories.append(cat)
    elif 'offers' in description and 'services' in description:
        # More specific pattern
        import re
        match = re.search(r'offers[^.]*services[^.]*in\s+([^\.]+)', description)
        if match:
            service_part = match.group(1)
            raw_cats = re.split(r',|, and|and', service_part)
            for cat in raw_cats:
                cat = cat.strip()
                if cat:
                    categories.append(cat)
    else:
        # Try to find any category list patterns
        import re
        match = re.search(r'\bincluding\s+([^\.]+)', description)
        if match:
            service_part = match.group(1)
            raw_cats = re.split(r',|, and|and', service_part)
            for cat in raw_cats:
                cat = cat.strip()
                if cat:
                    categories.append(cat)

    business_id_trimmed = business_id.replace('businessid_', '')
    business_categories[business_id_trimmed] = categories

# Map business_ref to categories
